## `source/schema.mjs`

```js
import { sqliteTable, integer, text } from 'drizzle-orm/sqlite-core';

export const users = sqliteTable('users', {
  id: integer('id').primaryKey({ autoIncrement: true }),
  name: text('name').notNull(),
  email: text('email').notNull().unique(),
});
```

## `source/repository.mjs` (GREEN / fixed version)

```js
import { eq, sql } from 'drizzle-orm';
import { users } from './schema.mjs';

export function createUser(db, { name, email }) {
  db.insert(users).values({ name, email }).run();
  // last_insert_rowid() alternative to .returning() — both work in 0.45.2
  const row = db.get(sql`select last_insert_rowid() as id`);
  return getUser(db, row.id);
}

export function getUser(db, id) {
  // FIXED: was eq(users.name, String(id)) — the RED bug
  return db.select().from(users).where(eq(users.id, id)).get();
}

export function listUsers(db) {
  return db.select().from(users).all();
}

export function updateUser(db, id, patch) {
  db.update(users).set(patch).where(eq(users.id, id)).run();
  return getUser(db, id);
}

export function deleteUser(db, id) {
  db.delete(users).where(eq(users.id, id)).run();
}
```

### RED variant (the bug this POC exists to catch)

```js
export function getUser(db, id) {
  // BUG: comparing name column to a stringified id — never matches
  return db.select().from(users).where(eq(users.name, String(id))).get();
}
```

`getUser(db, 1)` after `createUser(db, {name:'Alice', ...})` → SQL becomes
`select ... from "users" where "users"."name" = ?` with `params: ["1"]`, which matches nothing since the row's `name` is `"Alice"`, not `"1"`. Returns `undefined`, and `assert.ok(user !== undefined)` throws.

### The fix (one-line diff)

```diff
- return db.select().from(users).where(eq(users.name, String(id))).get();
+ return db.select().from(users).where(eq(users.id, id)).get();
```

