## 2. Config surface — `source/capstone/agent.config.ts`

All customization knobs live here. This is the file a downstream customizer touches — never the agent/tool logic.

```ts
// source/capstone/agent.config.ts
//
// Config surface for the env-field-officer agent.
// ENV overrides let a customizer change behavior with ZERO code edits:
//   AGENT_MODEL   — swap the model
//   AGENT_PERSONA — swap the instructions/persona
//   AGENT_TOOLS   — comma-separated subset of: get_weather,get_air_quality,get_world_time

const DEFAULT_MODEL = "claude-sonnet-4-5-20250929";

const DEFAULT_PERSONA = `You are an environmental field officer.
Report weather, air quality, and local time data tersely.
One line per data point. Numbers first, units always. No pleasantries, no markdown headers.
If a tool call fails, state which tool failed and why, in one line, and continue with the rest.`;

const DEFAULT_ENABLED_TOOLS = ["get_weather", "get_air_quality", "get_world_time"] as const;

function parseEnabledTools(raw: string | undefined): string[] {
  if (!raw) return [...DEFAULT_ENABLED_TOOLS];
  return raw
    .split(",")
    .map(s => s.trim())
    .filter(Boolean);
}

export const config = {
  model: process.env.AGENT_MODEL?.trim() || DEFAULT_MODEL,
  persona: process.env.AGENT_PERSONA?.trim() || DEFAULT_PERSONA,
  enabledToolNames: parseEnabledTools(process.env.AGENT_TOOLS),
};
```

