## 6. The reconciled + config-driven agent — `source/capstone/agent.ts`

```ts
// source/capstone/agent.ts
import { defineAgent } from "@flue/runtime";
import { z } from "zod";
import { config } from "./agent.config";
import { getWeatherTool } from "./tools/get-weather";
import { getAirQualityTool } from "./tools/get-air-quality";
import { getWorldTimeTool } from "./tools/get-world-time";

// Explicit wiring — Flue does NOT auto-discover tools from the filesystem
// (contrast with Eve's convention-based discovery in L1). Every tool must
// be imported and listed here, and it's filtered by the config surface so
// AGENT_TOOLS=get_weather,get_world_time works with zero code edits.
const ALL_TOOLS = {
  get_weather: getWeatherTool,
  get_air_quality: getAirQualityTool,
  get_world_time: getWorldTimeTool,
} as const;

const wiredTools = config.enabledToolNames
  .filter((n): n is keyof typeof ALL_TOOLS => n in ALL_TOOLS)
  .map(n => ALL_TOOLS[n]);

export default defineAgent({
  name: "weather",
  model: config.model,
  instructions: config.persona,
  input: z.object({
    message: z.string().describe("User's natural-language request"),
  }),
  tools: wiredTools,
  async run(ctx) {
    // ctx.complete() drives the built-in model+tool-call loop using the
    // agent's configured model/instructions/tools above. If your installed
    // @flue/runtime exposes a differently-named completion primitive,
    // swap it in here — this is the one line most likely to need adjusting
    // against the real package.
    return ctx.complete(ctx.input.message);
  },
});
```

