```js
// config-loader.mjs
//
// Typed config/env loader + request-body validator helper.
// Integrates: branded/coerced fields, enum, url() validator,
// optional().default(), safeParse-based 422 shaping, and a
// formatted ConfigError carrying the raw ZodError.issues.

import { z } from 'zod';

/**
 * AppConfigSchema
 * ----------------
 * host        — non-empty string
 * port        — coerced to number, int, 1..65535, branded 'Port'
 * dbUrl       — must be a valid URL string
 * logLevel    — one of a fixed enum
 * maxRetries  — coerced to number, int, 0..10, optional, defaults to 3
 */
export const AppConfigSchema = z.object({
  host: z.string().min(1),
  port: z.coerce.number().int().min(1).max(65535).brand('Port'),
  dbUrl: z.string().url(),
  logLevel: z.enum(['debug', 'info', 'warn', 'error']),
  maxRetries: z.coerce.number().int().min(0).max(10).optional().default(3),
});

/**
 * ConfigError
 * -----------
 * Thrown by load() on validation failure. Carries:
 *  - message: human-readable, multi-line, one bullet per issue (field path + message)
 *  - issues:  the raw ZodError.issues array (untouched, for programmatic inspection)
 */
export class ConfigError extends Error {
  constructor(message, issues) {
    super(message);
    this.name = 'ConfigError';
    this.issues = issues;
  }
}

/**
 * load(raw)
 * ---------
 * Parses `raw` against AppConfigSchema.
 * Returns the fully-typed, coerced config object on success.
 * Throws ConfigError (with formatted message + raw issues) on failure.
 */
export function load(raw) {
  const result = AppConfigSchema.safeParse(raw);

  if (!result.success) {
    const issues = result.error.issues;
    const message =
      'Invalid config:\n' +
      issues
        .map((issue) => `  - ${issue.path.join('.') || '(root)'}: ${issue.message}`)
        .join('\n');
    throw new ConfigError(message, issues);
  }

  return result.data;
}

/**
 * validateRequestBody(schema, body)
 * ----------------------------------
 * Generic HTTP-handler-shaped validator.
 * Returns { status: 200, data }               on success
 * Returns { status: 422, errors: [{path, message}] } on failure
 */
export function validateRequestBody(schema, body) {
  const result = schema.safeParse(body);

  if (!result.success) {
    const errors = result.error.issues.map((issue) => ({
      path: issue.path.join('.') || '(root)',
      message: issue.message,
    }));
    return { status: 422, errors };
  }

  return { status: 200, data: result.data };
}
