import { NextRequest, NextResponse } from "next/server";

// Next.js 16: the file must be named proxy.ts (not middleware.ts) and the
// exported function must be named `proxy` (not `middleware`). Using the old
// name/export silently no-ops — it does NOT throw, which cost me an hour
// debugging why redirects weren't happening.
export function proxy(request: NextRequest) {
  const session = request.cookies.get("session");

  if (!session) {
    const url = request.nextUrl.clone();
    url.pathname = "/login";
    return NextResponse.redirect(url, 307);
  }

  return NextResponse.next();
}

