### `app/api/chat/route.ts` (real Anthropic streaming, no mocks)

```ts
import Anthropic from "@anthropic-ai/sdk";

// Node runtime required: the Anthropic SDK's default transport relies on
// Node's fetch/agent internals in v0.32.x. Edge runtime works in newer SDK
// betas but wasn't reliable enough for this POC — pin to nodejs explicitly.
export const runtime = "nodejs";

const anthropic = new Anthropic({
  apiKey: process.env.ANTHROPIC_API_KEY,
});

export async function POST(req: Request) {
  const { prompt } = await req.json();

  if (!prompt || typeof prompt !== "string") {
    return Response.json({ error: "prompt (string) is required" }, { status: 400 });
  }

  const encoder = new TextEncoder();

  const stream = new ReadableStream({
    async start(controller) {
      const messageStream = anthropic.messages.stream({
        model: "claude-sonnet-4-5-20250929",
        max_tokens: 1024,
        messages: [{ role: "user", content: prompt }],
      });

      // Abort the upstream request if the client disconnects.
      req.signal.addEventListener("abort", () => {
        messageStream.abort();
      });

      try {
        // Iterating the MessageStream directly yields raw
        // RawMessageStreamEvent objects: message_start,
        // content_block_start, content_block_delta, content_block_stop,
        // message_delta, message_stop.
        for await (const event of messageStream) {
          if (event.type === "message_start") {
            const { id, model } = event.message;
            controller.enqueue(encoder.encode(`META ${id} ${model}\n`));
          } else if (
            event.type === "content_block_delta" &&
            event.delta.type === "text_delta"
          ) {
            controller.enqueue(encoder.encode(event.delta.text));
          }
        }
        controller.close();
      } catch (err) {
        controller.error(err);
      }
    },
  });

  return new Response(stream, {
    headers: {
      "Content-Type": "text/plain; charset=utf-8",
      "Cache-Control": "no-cache",
    },
  });
}
```

