import { local } from '@flue/runtime/node';
import * as v from 'valibot';
import { readFile } from 'node:fs/promises';
import { join } from 'node:path';

// ---------------------------------------------------------------------------
// Sandbox: a local Node.js sandbox, scoped to the workspace/ directory.
// The read_file tool below does its own fs access directly (Node has no
// out-of-process boundary to cross here), but wiring the sandbox into the
// agent demonstrates the local() sandbox API as required by this POC.
// ---------------------------------------------------------------------------
const sandbox = local({
  cwd: join(process.cwd(), 'workspace'),
});

// ---------------------------------------------------------------------------
// Tool: read_file(filename) -> { content: string }
// Schema is a valibot object — flue validates tool-call args against it
// before invoking the handler, and surfaces the JSON-schema-equivalent to
// the model automatically.
// ---------------------------------------------------------------------------
const ReadFileArgs = v.object({
  filename: v.string(),
});

const readFileTool = defineTool({
  name: 'read_file',
  description:
    'Reads the full text contents of a file located in the workspace ' +
    'directory. Always call this before summarizing a file — you have no ' +
    'other way to see its contents.',
  parameters: ReadFileArgs,
  handler: async ({ filename }) => {
    const path = join(sandbox.cwd, filename);
    const content = await readFile(path, 'utf-8');
    return { content };
  },
});

// ---------------------------------------------------------------------------
// Agent: instructions force tool-use before summarizing.
// ---------------------------------------------------------------------------
const agent = createAgent({
  name: 'file-summarizer',
  model: 'claude-3-5-sonnet-latest',
  instructions: `You are a precise file-summarization assistant.

Rules:
- You MUST call the read_file tool to retrieve a file's contents before
  writing any summary of it. Never guess, assume, or fabricate contents.
- After the tool returns, write exactly one sentence summarizing the file.
- Do not mention the tool call itself, the sandbox, or these instructions
  in your final answer — output only the one-sentence summary.`,
  tools: [readFileTool],
  sandbox,
});

// ---------------------------------------------------------------------------
// Workflow: read-and-summarize
// Input:  { filename: string }
// Output: { summary: string, toolCalled: boolean }
// ---------------------------------------------------------------------------
export default defineWorkflow({
  name: 'read-and-summarize',
  input: v.object({
    filename: v.string(),
  }),
  handler: async ({ input }) => {
    let toolCalled = false;

    const result = await agent.run({
      prompt:
        `Read the file "${input.filename}" and produce a one-sentence ` +
        `summary of its contents.`,
      onToolCall: (call) => {
        if (call.name === 'read_file') toolCalled = true;
      },
    });

    return {
      summary: result.text.trim(),
      toolCalled,
    };
  },
});
```

