#!/usr/bin/env node
import { spawn } from 'node:child_process';

const mode = process.argv[2];
if (!mode || !['red', 'green'].includes(mode)) {
  console.error('Usage: node run-and-assert.mjs <red|green>');
  process.exit(2);
}

function runWorkflow(payload) {
  return new Promise((resolve) => {
    const args = [
      'flue',
      'run',
      'read-and-summarize',
      '--target',
      'node',
      '--payload',
      JSON.stringify(payload),
    ];
    const child = spawn('npx', args, {
      cwd: process.cwd(),
      stdio: ['ignore', 'pipe', 'pipe'],
    });
    let stdout = '';
    let stderr = '';
    child.stdout.on('data', (d) => (stdout += d));
    child.stderr.on('data', (d) => (stderr += d));
    child.on('close', (code) => resolve({ code, stdout, stderr }));
  });
}

function extractJson(stdout) {
  const lines = stdout.trim().split('\n');
  for (let i = lines.length - 1; i >= 0; i--) {
    try {
      return JSON.parse(lines[i]);
    } catch {
      continue;
    }
  }
  throw new Error('No JSON result line found in flue run output:\n' + stdout);
}

async function main() {
  console.log(
    `\n=== ${mode.toUpperCase()} run: read-and-summarize (input.txt) ===\n`,
  );
  const { code, stdout, stderr } = await runWorkflow({ filename: 'input.txt' });
  console.log(stdout);
  if (stderr) console.error(stderr);

  if (code !== 0) {
    console.error(`flue run exited with code ${code} — cannot evaluate assertions.`);
    process.exit(1);
  }

  const result = extractJson(stdout);
  console.log('Parsed result:', result);

  const assertions = [];

  if (mode === 'red') {
    // RED is a deliberately-wrong assertion, proving this harness can fail:
    // a correctly grounded summary of input.txt (Eiffel Tower) must NOT
    // mention "Python". If this assertion ever passes, the grounding is
    // broken (the model hallucinated/mixed content) — that's the point of
    // running RED before GREEN.
    assertions.push({
      name: 'summary incorrectly mentions "Python" (expected to fail)',
      pass: /python/i.test(result.summary),
    });
  } else {
    assertions.push({
      name: 'toolCalled === true',
      pass: result.toolCalled === true,
    });
    assertions.push({
      name: 'summary references Eiffel/Paris/Tower',
      pass: /eiffel|paris|tower/i.test(result.summary),
    });
    assertions.push({
      name: 'summary is non-empty and ~one sentence',
      pass:
        typeof result.summary === 'string' &&
        result.summary.trim().length > 0 &&
        result.summary.trim().split(/(?<=[.!?])\s+/).length <= 2,
    });
  }

  let allPass = true;
  for (const a of assertions) {
    console.log(`${a.pass ? 'PASS' : 'FAIL'} — ${a.name}`);
    if (!a.pass) allPass = false;
  }

  if (mode === 'green') {
    console.log('\n=== GREEN regression: second.txt (Python) ===\n');
    const second = await runWorkflow({ filename: 'second.txt' });
    console.log(second.stdout);
    if (second.code !== 0) {
      console.error('Regression run failed to execute.');
      allPass = false;
    } else {
      const secondResult = extractJson(second.stdout);
      const pass =
        secondResult.toolCalled === true && /python/i.test(secondResult.summary);
      console.log(
        `${pass ? 'PASS' : 'FAIL'} — regression: toolCalled + summary mentions Python`,
      );
      if (!pass) allPass = false;
    }
  }

  process.exit(allPass ? 0 : 1);
}

main().catch((err) => {
  console.error(err);
  process.exit(1);
});
