```js
// lib/pi-adapter.mjs
//
// Thin adapter over the Pi agent-session call surface. The exact method
// name (`act` / `run` / `prompt`) is not something I've independently
// verified against the real `agentos` package, so this tries the plausible
// shapes in order rather than assuming one. If the real package exposes
// something else, add a branch here — the rest of the probes only depend
// on `runTurn()` and `extractText()`.

export async function runTurn(session, prompt) {
  if (typeof session.act === 'function') return session.act({ prompt });
  if (typeof session.run === 'function') return session.run({ prompt });
  if (typeof session.prompt === 'function') return session.prompt(prompt);
  throw new Error(
    'Unrecognized Pi session API surface — update runTurn() in lib/pi-adapter.mjs'
  );
}

export function extractText(result) {
  if (typeof result === 'string') return result;
  if (!result || typeof result !== 'object') return String(result);
  return (
    result.output ??
    result.text ??
    result.message ??
    result.content ??
    JSON.stringify(result)
  );
}

export function requireApiKey() {
  if (!process.env.ANTHROPIC_API_KEY) {
    throw new Error(
      'ANTHROPIC_API_KEY is required — this probe drives two live Claude round-trips.'
    );
  }
}
```

## `probe-capstone2.mjs` — the graded GREEN path (sequential, top-level host calls)

```js
// probe-capstone2.mjs
//
// Agent-to-agent review, GREEN state: coder and reviewer are driven as
// SEQUENTIAL top-level host calls. Nothing is nested inside a binding
// `execute` while another action is in flight, so there is no shared
// wasm_fuel_ms budget to exhaust between the two agent turns.
//
// Flow:
//   1. boot coder VM
//   2. coder Pi session writes /workspace/math.js with a deliberate bug
//   3. host reads the file out of the coder VM
//   4. boot an independent reviewer VM
//   5. host writes the file into the reviewer VM
//   6. reviewer Pi session reads it and is asked to judge add()
//   7. assert the reviewer's verdict flags the bug
//   8. dispose both VMs

import { AgentOs } from 'agentos';
import { pi } from 'agentos/software/pi';
import { runTurn, extractText, requireApiKey } from './lib/pi-adapter.mjs';

const FILE_PATH = '/workspace/math.js';

const BUGGY_SOURCE_PROMPT = `
Create the file ${FILE_PATH} with exactly this content: a module exporting
a function \`add(a, b)\` that returns \`a - b\` (yes — subtraction, not
addition; this is a deliberately injected bug for a test fixture). Use your
file-write tool. Do not explain, just write the file.
`;

const REVIEW_PROMPT = `
Read the file ${FILE_PATH}. Look specifically at the function \`add(a, b)\`.
Does it correctly compute the sum a + b? Answer with a clear verdict:
say "BUG" and name the bug if it is wrong, or "OK" if it is correct.
`;

function looksLikeBugCaught(verdictText) {
  return /\bbug\b/i.test(verdictText) &&
    /(subtract|minus|a\s*-\s*b|incorrect|wrong)/i.test(verdictText);
}

async function main() {
  requireApiKey();
  const t0 = Date.now();

  // --- Step 1-2: coder VM, coder agent writes the buggy file -------------
  const coder = await AgentOs.create({ software: [pi] });
  const coderSession = await coder.pi.session();
  await runTurn(coderSession, BUGGY_SOURCE_PROMPT);

  // --- Step 3: host reads the artifact OUT of the coder VM ---------------
  const source = await coder.readFile(FILE_PATH);
  console.log('[host] coder VM produced:\n' + source);

  // --- Step 4: independent reviewer VM, booted fresh ----------------------
  const reviewer = await AgentOs.create({ software: [pi] });

  // --- Step 5: host writes the artifact INTO the reviewer VM --------------
  await reviewer.writeFile(FILE_PATH, source);

  // --- Step 6: reviewer agent reads + judges the file ---------------------
  const reviewerSession = await reviewer.pi.session();
  const reviewResult = await runTurn(reviewerSession, REVIEW_PROMPT);
  const verdict = extractText(reviewResult);
  console.log('[reviewer] verdict:\n' + verdict);

  // --- Step 7: assert the bug was caught -----------------------------------
  const caught = looksLikeBugCaught(verdict);

  // --- Step 8: dispose both VMs ---------------------------------------------
  await coder.dispose();
  await reviewer.dispose();

  const total = Date.now() - t0;

  if (caught) {
    console.log(`=> CAPSTONE-SEQ PASS (reviewer caught the bug) total ${total} ms`);
  } else {
    console.log(`=> CAPSTONE-SEQ FAIL (reviewer missed the bug) total ${total} ms`);
    process.exitCode = 1;
  }
}

main().catch((err) => {
  console.error('CAPSTONE-SEQ ERROR:', err);
  process.exitCode = 1;
});
```

