```ts
// Vite plugin: server-side /api/chat proxy.
// Runs in Node (Vite dev server), never in the browser bundle.
// ANTHROPIC_API_KEY is read from process.env here only.

import type { Plugin, Connect } from 'vite';
import Anthropic from '@anthropic-ai/sdk';
import { openuiLibrary, openuiPromptOptions } from '@openuidev/react';

const MODEL = 'claude-sonnet-4-6';
const MAX_TOKENS = 1600;

// Cache the built-in system prompt across requests — openuiLibrary.prompt()
// walks the full component registry and is not free; no reason to redo it
// on every chat turn within a single dev-server lifetime.
let promptCache: string | null = null;
function getSystemPrompt(): string {
  if (promptCache === null) {
    promptCache = openuiLibrary.prompt(openuiPromptOptions);
  }
  return promptCache;
}

interface IncomingChatMessage {
  role: 'user' | 'assistant' | 'system';
  content: string;
}

async function readBody(req: Connect.IncomingMessage): Promise<string> {
  const chunks: Buffer[] = [];
  for await (const chunk of req) {
    chunks.push(Buffer.isBuffer(chunk) ? chunk : Buffer.from(chunk));
  }
  return Buffer.concat(chunks).toString('utf8');
}

export function chatPlugin(): Plugin {
  return {
    name: 'openui-chat-proxy',
    configureServer(server) {
      server.middlewares.use('/api/chat', async (req, res) => {
        if (req.method !== 'POST') {
          res.statusCode = 405;
          res.end('Method Not Allowed');
          return;
        }

        const apiKey = process.env.ANTHROPIC_API_KEY;
        if (!apiKey) {
          res.statusCode = 500;
          res.setHeader('Content-Type', 'application/json');
          res.end(JSON.stringify({ error: 'ANTHROPIC_API_KEY not set' }));
          return;
        }

        let payload: { messages: IncomingChatMessage[] };
        try {
          payload = JSON.parse(await readBody(req));
        } catch {
          res.statusCode = 400;
          res.end(JSON.stringify({ error: 'invalid JSON body' }));
          return;
        }

        // Anthropic wants `system` as a separate top-level field, not a
        // message in the array — strip any `system` role entries the
        // client-side thread state may carry.
        const messages = (payload.messages ?? [])
          .filter((m) => m.role === 'user' || m.role === 'assistant')
          .map((m) => ({ role: m.role, content: m.content }));

        const anthropic = new Anthropic({ apiKey });
        const system = getSystemPrompt();

        res.writeHead(200, {
          'Content-Type': 'text/event-stream',
          'Cache-Control': 'no-cache',
          Connection: 'keep-alive',
        });

        try {
          const stream = anthropic.messages.stream({
            model: MODEL,
            max_tokens: MAX_TOKENS,
            system,
            messages,
          });

          // stream.textStream is the real @anthropic-ai/sdk convenience
          // async-iterable that yields only text deltas (already
          // de-multiplexed from content_block_start / delta / stop events).
          for await (const text of stream.textStream) {
            const ssePayload = { choices: [{ delta: { content: text } }] };
            res.write(`data: ${JSON.stringify(ssePayload)}\n\n`);
          }

          // Draining finalMessage() surfaces any mid-stream error
          // (rate limit, overloaded_error, stop_reason issues) before we
          // close the response.
          await stream.finalMessage();
          res.write('data: [DONE]\n\n');
        } catch (err) {
          const message = err instanceof Error ? err.message : String(err);
          res.write(
            `data: ${JSON.stringify({
              choices: [{ delta: { content: `\n\n[stream error: ${message}]` } }],
            })}\n\n`
          );
          res.write('data: [DONE]\n\n');
        } finally {
          res.end();
        }
      });
    },
  };
}
```

