```tsx
import { useState, useCallback } from 'react';
import {
  ChatProvider,
  useThread,
  fetchLLM,
  openAIAdapter,
  openAIMessageFormat,
} from '@openuidev/react-headless';
import { Renderer, openuiLibrary } from '@openuidev/react';

const PREFILLED_PROMPT =
  'Show me Q3 revenue by region as a bar chart, plus a summary card highlighting the top region.';

function Bubble({
  role,
  content,
  isStreaming,
}: {
  role: 'user' | 'assistant';
  content: string;
  isStreaming: boolean;
}) {
  return (
    <div className={`bubble bubble-${role}`} data-role={role}>
      {role === 'assistant' ? (
        <Renderer library={openuiLibrary} response={content} isStreaming={isStreaming} />
      ) : (
        <p>{content}</p>
      )}
    </div>
  );
}

function ChatPanel() {
  const { messages, isRunning, processMessage } = useThread();
  const [input, setInput] = useState(PREFILLED_PROMPT);

  const onSend = useCallback(async () => {
    if (!input.trim() || isRunning) return;
    const text = input;
    setInput('');

    // processMessage drives the headless thread's state machine
    // (adds the user turn, opens an assistant turn, streams deltas into
    // it, flips isRunning back to false on completion/error).
    await processMessage(text, {
      fetch: (openAIPayload) =>
        fetchLLM({
          url: '/api/chat',
          adapter: openAIAdapter(),
          messageFormat: openAIMessageFormat,
          payload: openAIPayload,
        }),
    });
  }, [input, isRunning, processMessage]);

  const lastId = messages.length ? messages[messages.length - 1].id : null;

  return (
    <div className="chat-panel">
      <div className="chat-thread" data-testid="chat-thread">
        {messages.map((m) => (
          <Bubble
            key={m.id}
            role={m.role}
            content={m.content}
            isStreaming={isRunning && m.id === lastId}
          />
        ))}
      </div>

      <div className="chat-input-row">
        <input
          data-testid="chat-input"
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={(e) => e.key === 'Enter' && onSend()}
        />
        <button data-testid="chat-send" onClick={onSend} disabled={isRunning}>
          Send
        </button>
      </div>

      {/* Sentinel for Playwright: waits on data-running rather than
          polling for arbitrary DOM stability. */}
      <div data-testid="chat-sentinel" data-running={isRunning ? '1' : '0'} />
    </div>
  );
}

export default function L9Harness() {
  return (
    <ChatProvider>
      <ChatPanel />
    </ChatProvider>
  );
}
