### `app.mjs`

```js
import { Hono } from 'hono'
import { secureHeaders } from 'hono/secure-headers'
import { cors } from 'hono/cors'
import { zValidator } from '@hono/zod-validator'
import { z } from 'zod'
import { SignJWT, jwtVerify } from 'jose'

// ---- JWT (HS256, in-memory secret — test-only) ----
const JWT_SECRET = new TextEncoder().encode(
  'capstone-test-secret-do-not-use-in-prod'
)

export async function signToken(payload = { sub: 'test-user' }) {
  return await new SignJWT(payload)
    .setProtectedHeader({ alg: 'HS256' })
    .setIssuedAt()
    .setExpirationTime('1h')
    .sign(JWT_SECRET)
}

// ---- In-memory store ----
export let items = []
let nextId = 1

export function resetStore() {
  items = []
  nextId = 1
}

// ---- Schema ----
const itemBody = z.object({
  name: z.string().min(1),
  qty: z.number().int().nonnegative(),
})

// ---- Bearer guard ----
const bearerGuard = async (c, next) => {
  const auth = c.req.header('Authorization') || ''
  const match = auth.match(/^Bearer\s+(.+)$/)
  if (!match) {
    return c.json({ error: 'unauthorized' }, 401)
  }
  try {
    await jwtVerify(match[1], JWT_SECRET)
  } catch {
    return c.json({ error: 'unauthorized' }, 401)
  }
  await next()
}

// ---- App ----
const app = new Hono()

app.use('*', secureHeaders())
app.use(
  '*',
  cors({
    origin: 'https://example.com',
    allowMethods: ['GET', 'POST', 'PUT', 'DELETE'],
  })
)

app.get('/items', (c) => c.json(items))

app.get('/items/:id', (c) => {
  const id = Number(c.req.param('id'))
  const item = items.find((i) => i.id === id)
  if (!item) return c.json({ error: 'not found' }, 404)
  return c.json(item)
})

app.post('/items', bearerGuard, zValidator('json', itemBody), (c) => {
  const body = c.req.valid('json')
  const item = { id: nextId++, ...body }
  items.push(item)
  return c.json(item, 201)
})

app.put('/items/:id', bearerGuard, zValidator('json', itemBody), (c) => {
  const id = Number(c.req.param('id'))
  const idx = items.findIndex((i) => i.id === id)
  if (idx === -1) return c.json({ error: 'not found' }, 404)
  const body = c.req.valid('json')
  items[idx] = { id, ...body }
  return c.json(items[idx], 200)
})

// GREEN: guarded. (RED bug omitted `bearerGuard` here — see note below.)
app.delete('/items/:id', bearerGuard, (c) => {
  const id = Number(c.req.param('id'))
  const idx = items.findIndex((i) => i.id === id)
  if (idx === -1) return c.json({ error: 'not found' }, 404)
  items.splice(idx, 1)
  return new Response(null, { status: 204 })
})

export default app
```

