## File: `source/auth-middleware.mjs`

```js
import { jwtVerify } from 'jose';

/**
 * verifyToken - a safe wrapper around jose's jwtVerify() that enforces the
 * secure defaults jose does NOT apply automatically:
 *
 *   - audience validation (`aud` claim)
 *   - issuer validation (`iss` claim)
 *   - algorithm allowlist (`alg` header)
 *
 * VERIFIED GOTCHA: jose's raw jwtVerify(jwt, key) will happily accept a
 * token with ANY `aud` / `iss` value if you don't pass those options
 * explicitly. This wrapper makes those options mandatory so a caller can
 * never accidentally ship a verifier that skips them.
 *
 * @param {string} jwt - compact JWS string
 * @param {import('jose').CryptoKey | Uint8Array} key - verification key
 * @param {{
 *   audience: string | string[],
 *   issuer: string | string[],
 *   algorithms: string[]
 * }} opts
 * @returns {Promise<import('jose').JWTVerifyResult>}
 */
export async function verifyToken(jwt, key, opts = {}) {
  const { audience, issuer, algorithms } = opts;

  if (!audience) {
    throw new Error(
      'verifyToken: "audience" is required — refusing to verify without an ' +
      'audience check (jose does not enforce aud by default)'
    );
  }
  if (!issuer) {
    throw new Error(
      'verifyToken: "issuer" is required — refusing to verify without an ' +
      'issuer check (jose does not enforce iss by default)'
    );
  }
  if (!Array.isArray(algorithms) || algorithms.length === 0) {
    throw new Error(
      'verifyToken: "algorithms" allowlist (non-empty array) is required — ' +
      'refusing to verify without an algorithm allowlist'
    );
  }

  return jwtVerify(jwt, key, { audience, issuer, algorithms });
}

/**
 * createVerifier - factory that pre-binds a verification key + options,
 * returning a single-argument verifier function: (jwt) => Promise<...>
 *
 * @param {import('jose').CryptoKey | Uint8Array} key
 * @param {{
 *   audience: string | string[],
 *   issuer: string | string[],
 *   algorithms: string[]
 * }} opts
 * @returns {(jwt: string) => Promise<import('jose').JWTVerifyResult>}
 */
export function createVerifier(key, opts) {
  return (jwt) => verifyToken(jwt, key, opts);
}
```

