test('verifyToken rejects tampered JWT → JWSSignatureVerificationFailed', async () => {
  const { publicKey, privateKey } = await generateKeyPair('ES256');
  const jwt = await signJWT(privateKey);
  const tampered = tamper(jwt);

  await assert.rejects(
    () => verifyToken(tampered, publicKey, { audience: AUD, issuer: ISS, algorithms: ['ES256'] }),
    (err) => {
      console.log(`  tamper rejection: ${err.constructor.name} code=${err.code}`);
      assert.equal(err.constructor.name, 'JWSSignatureVerificationFailed');
      assert.equal(err.code, 'ERR_JWS_SIGNATURE_VERIFICATION_FAILED');
      return true;
    }
  );
});

test('verifyToken rejects expired JWT (past exp, no sleep) → JWTExpired', async () => {
  const { publicKey, privateKey } = await generateKeyPair('ES256');
  const jwt = await signJWT(privateKey, { expOffsetSec: -30 });

  await assert.rejects(
    () => verifyToken(jwt, publicKey, { audience: AUD, issuer: ISS, algorithms: ['ES256'] }),
    (err) => {
      console.log(`  expiry rejection: ${err.constructor.name} code=${err.code}`);
      assert.equal(err.constructor.name, 'JWTExpired');
      assert.equal(err.code, 'ERR_JWT_EXPIRED');
      return true;
    }
  );
});

test('verifyToken happy path: valid token with correct aud/iss/alg → verified payload', async () => {
  const { publicKey, privateKey } = await generateKeyPair('ES256');
  const jwt = await signJWT(privateKey);

  const { payload } = await verifyToken(jwt, publicKey, {
    audience: AUD,
    issuer: ISS,
    algorithms: ['ES256'],
  });

  console.log(
    `  verified payload: sub=${payload.sub} aud=${payload.aud} iss=${payload.iss} ` +
    `iat=${payload.iat} exp=${payload.exp}`
  );

  assert.equal(payload.sub, SUB);
  assert.equal(payload.aud, AUD);
  assert.equal(payload.iss, ISS);
  assert.equal(typeof payload.iat, 'number');
  assert.equal(typeof payload.exp, 'number');
});

test('createVerifier factory: single-arg verifier rejects wrong aud and accepts correct token', async () => {
  const { publicKey, privateKey } = await generateKeyPair('ES256');
  const verify = createVerifier(publicKey, { audience: AUD, issuer: ISS, algorithms: ['ES256'] });

  const wrongAudJwt = await signJWT(privateKey, { aud: 'other-service' });
  const correctJwt = await signJWT(privateKey);

  await assert.rejects(
    () => verify(wrongAudJwt),
    (err) => err.constructor.name === 'JWTClaimValidationFailed'
  );

  const { payload } = await verify(correctJwt);
  assert.equal(payload.sub, SUB);

  console.log(
    `  createVerifier: rejected wrong-aud (JWTClaimValidationFailed), ` +
    `accepted correct token (sub=${payload.sub})`
  );
});
