## File: `source/parse-vs-safeparse.test.mjs`

```js
import { test } from 'node:test';
import assert from 'node:assert/strict';
import { z } from 'zod';

// --- Domain: user schema, Zod v4 canonical forms ---
const UserSchema = z.object({
  name: z.string(),
  age: z.number().int().positive(),
  email: z.email(), // v4 top-level email validator (not z.string().email())
});

const badInput = { name: 123, age: 'not-a-number', email: 'bad' };
const goodInput = { name: 'Alice', age: 30, email: 'alice@example.com' };

test('L0 — parse vs safeParse (Zod 4 canonical seam)', async (t) => {

  await t.test('safeParse(badInput) returns {success:false, error: ZodError} with issues array', () => {
    const result = UserSchema.safeParse(badInput);

    // GREEN assertion. Flip to `true` to reproduce the deliberate RED failure
    // described in the POC (exit code 1, 1 failing test).
    assert.equal(result.success, false);

    assert.ok(result.error instanceof z.ZodError);
    assert.ok(Array.isArray(result.error.issues));
    assert.ok(result.error.issues.length > 0);
  });

  await t.test('safeParse(goodInput) returns {success:true, data}', () => {
    const result = UserSchema.safeParse(goodInput);
    assert.equal(result.success, true);
    assert.deepEqual(result.data, goodInput);
  });

  await t.test('.parse(badInput) throws ZodError', () => {
    assert.throws(
      () => UserSchema.parse(badInput),
      (err) => {
        assert.ok(err instanceof z.ZodError);
        return true;
      }
    );
  });

  await t.test('ZodError.issues[0] has correct path, code, and message', () => {
    const result = UserSchema.safeParse(badInput);
    const issue = result.error.issues[0];

    // First issue is the `name` field — object keys are validated
    // in schema-definition order (name, age, email).
    assert.equal(issue.code, 'invalid_type');
    assert.deepEqual(issue.path, ['name']);
    assert.equal(issue.expected, 'string');

    // Zod v4 change: no `received` key on invalid_type issues (v3 had it).
    assert.equal('received' in issue, false);

    assert.ok(typeof issue.message === 'string' && issue.message.length > 0);
  });
});
```

